import{_ as a,o as i,c as o,ag as c}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Aliasy Chmod | Dotfiles (PL)","titleTemplate":":title","description":"Skrocone polecenia uprawnien. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","frontmatter":{"title":"Aliasy Chmod | Dotfiles","description":"Skrocone polecenia uprawnien. Przeglad dla Dotfiles v0.2.495. Kompatybilny z macOS, Linux i WSL przez Dotfiles.","lang":"pl-PL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Aliasy Chmod | Dotfiles preview","canonical":"/pl/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Aliasy Chmod","pageType":"docs","schemaType":"WebPage","permalink":"/pl/aliases/chmod/"},"headers":[],"relativePath":"pl/aliases/chmod/index.md","filePath":"pl/aliases/chmod/index.md","lastUpdated":1773010926000}'),l={name:"pl/aliases/chmod/index.md"};function d(n,e,s,t,r,p){return i(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="aliasy-chmod" tabindex="-1">Aliasy Chmod <a class="header-anchor" href="#aliasy-chmod" aria-label="Permalink to &quot;Aliasy Chmod&quot;">​</a></h1><p>Skrocone polecenia uprawnien.</p><p>Ta strona przedstawia jedna grupe aliasow i jej typowe skroty polecen. Przeczytaj ja najpierw, aby zrozumiec konwencje nazewnictwa, oczekiwane dane wejsciowe i bezpieczne wzorce wykonywania. Nastepnie otworz dodatek referencyjny, aby zobaczyc pelny spis polecen i dokladna skladnie. Te aliasy redukuja powtarzalne wpisywanie i zapewniaja spojne zachowanie przeplywy pracy na macOS, Linux i WSL.</p><h2 id="kiedy-uzywac" tabindex="-1">Kiedy uzywac <a class="header-anchor" href="#kiedy-uzywac" aria-label="Permalink to &quot;Kiedy uzywac&quot;">​</a></h2><p>Uzyj tej strony przed codziennym uzywaniem powloki, gdy potrzebujesz przewidywalnych wzorcow polecen.</p><h2 id="co-zawiera" tabindex="-1">Co zawiera <a class="header-anchor" href="#co-zawiera" aria-label="Permalink to &quot;Co zawiera&quot;">​</a></h2><ul><li>Aliasy: 17</li><li>Funkcje pomocnicze: 0</li><li>Pliki zrodlowe: 1</li></ul><h2 id="szybkie-przyklady" tabindex="-1">Szybkie przyklady <a class="header-anchor" href="#szybkie-przyklady" aria-label="Permalink to &quot;Szybkie przyklady&quot;">​</a></h2><ul><li><code>chmod_000</code> -&gt; <code>change_permission 000</code></li><li><code>chmod_1755</code> -&gt; <code>&#39;change_permission 1755&#39; # Sticky bit + 755</code></li><li><code>chmod_2755</code> -&gt; <code>&#39;change_permission 2755&#39; # Setgid + 755</code></li><li><code>chmod_400</code> -&gt; <code>&#39;change_permission 400&#39; # Tylko odczyt dla wlasciciela</code></li><li><code>chmod_444</code> -&gt; <code>&#39;change_permission 444&#39; # Tylko odczyt dla wszystkich</code></li><li><code>chmod_4755</code> -&gt; <code>&#39;change_permission 4755&#39; # Setuid + 755</code></li><li><code>chmod_600</code> -&gt; <code>&#39;change_permission 600&#39; # Odczyt/zapis dla wlasciciela</code></li><li><code>chmod_644</code> -&gt; <code>&#39;change_permission 644&#39; # Odczyt/zapis dla wlasciciela, odczyt dla innych</code></li><li><code>chmod_664</code> -&gt; <code>&#39;change_permission 664&#39; # Odczyt/zapis dla wlasciciela i grupy, odczyt dla innych</code></li><li><code>chmod_666</code> -&gt; <code>&#39;change_permission 666&#39; # Odczyt/zapis dla wszystkich</code></li><li><code>chmod_700</code> -&gt; <code>&#39;change_permission 700&#39; # Pelne dla wlasciciela</code></li><li><code>chmod_744</code> -&gt; <code>&#39;change_permission 744&#39; # Pelne dla wlasciciela, odczyt dla innych</code></li></ul><h2 id="nastepny-krok" tabindex="-1">Nastepny krok <a class="header-anchor" href="#nastepny-krok" aria-label="Permalink to &quot;Nastepny krok&quot;">​</a></h2><p>Otworz pelna liste:</p>',11)])])}const m=a(l,[["render",d]]);export{h as __pageData,m as default};
